def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        for j in range(1, 11):
            threshold = j * 0.1
            if ratio <= threshold:
                score += (11 - j) * np.log(j + 1) * np.cos(ratio * np.pi * j)
            else:
                penalty = j * np.sqrt(ratio) * (1 + (j % 3) * 0.1)
                if j % 2 == 0:
                    penalty *= 1.05
                else:
                    penalty *= 0.95
                score -= penalty
        if capacity % 3 == 0:
            score *= 1.15
            for k in range(1, 4):
                if (capacity // k) % 2 == 0:
                    score += np.log(k + 1) * ratio * 0.5
                else:
                    score -= np.sqrt(k + 1) * (1 - ratio) * 0.3
        else:
            score *= 0.85
            for m in range(5):
                if m == 0 or m == 4:
                    score += np.sin(ratio * np.pi * (m + 1)) * 0.2
                else:
                    score -= np.cos(ratio * np.pi * (m + 1)) * 0.1
        if score < 0:
            score = 0
        priorities[i] = score
    return priorities
